const byCarrier = new Map();
rows.forEach(r => {
  const v = byCarrier.get(r.carrier) || { carrier: r.carrier, late: 0 };
  v.late += r.late_flights;
  byCarrier.set(r.carrier, v);
});
const sorted = [...byCarrier.values()].sort((a, b) => b.late - a.late);
return [{ top1: sorted[0]?.carrier || '—', top1_late: sorted[0]?.late || 0, total_carriers: byCarrier.size }];

const byCarrier = new Map();
rows.forEach(r => {
  const v = byCarrier.get(r.carrier) || 0;
  byCarrier.set(r.carrier, v + r.late_flights);
});
return [...byCarrier.entries()].map(([carrier, late]) => ({ carrier, late })).sort((a, b) => b.late - a.late).slice(0, 10);
